#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

uvo = 0.5 + (vUv-0.5)*vec2(1.1,0.81);
factorA = vUv-vec2(1-0.5,0.5);
factorB = vec2(0,-1024);
product = vec2( factorA.x*factorB.x - factorA.y*factorB.y, factorA.x*factorB.y + factorA.y*factorB.x);
numerator = vec2(1,0);
denominator = product;
fraction = vec2( numerator.x*denominator.x + numerator.y*denominator.y,   // the fractions real part
                   numerator.y*denominator.x - numerator.x*denominator.y)/  // the fractions imaginary part
                   (denominator.x*denominator.x + denominator.y*denominator.y);
vUv = fraction.yx*vec2(-1,1)*100;
vUv = mix(0.5 + (uvo-0.5)*2,vUv+0.5,0.5);
vUv = 0.5 + (1.0 - abs( fract( vUv * 0.5 ) * 2 - 1.0 )-0.5)*0.98; // Eo.S. mirror code with cutted borders
vec2 base_uv = uv_aspect(vUvOriginal, vUv, uAspect.wz*0+1, 0);
vec2 pos1 = 1-vec2(q1,q5);
float rad1 = q9;
vec2 pos2 = 1-vec2(q2,q6);
float rad2 = q9;
vec2 pos3 = 1-vec2(q3,q7);
float rad3 = q9;
vec2 pos4 = 1-vec2(q4,q8);
float rad4 = q9;
vec3 col1 = vec3(2,1,-1);
vec3 col2 = vec3(2,-1,1);
vec3 col3 = vec3(-1,1,2);
vec3 col4 = vec3(1,-1,2);
float refractivity = 2;
vec2 lens_uv = uv_lens_half_sphere(vUv, pos1, rad1, refractivity);
       lens_uv = uv_lens_half_sphere(lens_uv, pos2, rad2, refractivity);
       lens_uv = uv_lens_half_sphere(lens_uv, pos3, rad3, refractivity);
       lens_uv = uv_lens_half_sphere(lens_uv, pos4, rad4, refractivity);

//vUv = lens_uv;
    vec2 d = uTexSize.zw*1.2;
    vec3 dx = ( GetPixel(vUv + vec2(1,0)*d) - GetPixel(vUv-vec2(1,0)*d) );
    vec3 dy = ( GetPixel(vUv + vec2(0,1)*d) - GetPixel(vUv-vec2(0,1)*d) );

    float c = 8;
    float dd = 1;
vec3 light1 = dd - pow(length(vUv-vec2(lum(dx),lum(dy))*c-pos1),.2);
vec3 light2 = dd - pow(length(vUv-vec2(lum(dx),lum(dy))*c-pos2),.2);
vec3 light3 = dd - pow(length(vUv-vec2(lum(dx),lum(dy))*c-pos3),.2);
vec3 light4 = dd - pow(length(vUv-vec2(lum(dx),lum(dy))*c-pos4),.2);

ret = mix(GetPixel(vUv),max(max(light1*col1,light2*col2),max(light3*col3,light4*col4)),0.5)*1.25;
vec4 noise9 = texture3D(sampler_noisevol_hq,
                      ((vec3(dy.z,dy.x,dx.z)*q28
                       )*uTexSize.xyy*texsize_noisevol_hq.zww
                      ).xyz*
                      vec3(1,1,0)*0.05 +
                      uTime*vec3(0,0,1)*q31
                     );
if(ret.x> q26*q13         && ret.x<= q23*q11        )ret.z -= (noise9).x*.5;
if(ret.y> q25*q11         && ret.y<= q22*q12        )ret.x -= (noise9).y*.5;
if(ret.z> q24*q12         && ret.z<= q21*q13        )ret.y -= (noise9).z*.5;


  fragColor = ret;
}
